#include<bits/stdc++.h>
using namespace std;
int a[1005][4],b[1005][4],n;
int f(int a[4],int b[4]){
    int c[4],sum=0;
    for(int i=0;i<4;i++)sum+=b[i];
    if(sum==0)return 0;
    for(int i=0;i<4;i++)c[i]=a[i]-b[i];
    for(int i=0;i<4;i++)
        if(c[i]==-1)return 0;
    for(int i=0;i<4;i++)
        if(c[i]==1)return 3;
    return 6;
}
int main(void){
	std::ios::sync_with_stdio(false);
	cin>>n;
	for(int i=0;i<n;i++)for(int j=0;j<4;j++)cin>>a[i][j];
	for(int i=0;i<n;i++)for(int j=0;j<4;j++)cin>>b[i][j];
	for(int i=0;i<n;i++){
	    int ans=0;
	    for(int j=0;j<n;j++)ans+=f(a[(i+j)%n],b[j]);
	    cout<<ans<<' ';
	}
	return false;
}
